Python<pre><code>class MnistDataset:
    def __init__(self, data_path, test=False):
        if not test: # ​根据​数据​集​的​真实情况​编写​代码​
            self.data = pd.read_csv(data_path).drop("label", axis=1)
        else:
            self.data = pd.read_csv(data_path)

    def __len__(self):
        return len(self.data)

    def __getitem__(self, index):
        item = self.data.iloc[index, :]
        img = item.to_numpy().reshape(1, 28, 28) / 255
        img = torch.tensor(img)
        return img, img # ​第一个​img​用于​加​噪声​，​第二个​img​用于​当作​标签​。
</code></pre>

